import{_ as e,o as t,c as p,f as i}from"./app-55c326ac.js";const o={},c=i('<h1 id="用一张图解释-8-种流行的网络协议" tabindex="-1"><a class="header-anchor" href="#用一张图解释-8-种流行的网络协议" aria-hidden="true">#</a> 用一张图解释 8 种流行的网络协议</h1><p>网络协议是在网络中的两台计算机之间传输数据的标准方法。</p><p><img src="https://substackcdn.com/image/fetch/w_1456,c_limit,f_auto,q_auto:good,fl_lossy/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F6f9e43fa-84d5-4875-817c-c2e1af75d16e_1280x1664.gif" alt="8 Popular Network Protocols" title="No alternative text description for this image"></p><ol><li><p>HTTP（超文本传输协议）</p><p>HTTP 是一种用于获取 HTML 文档等资源的协议。它是 Web 上任何数据交换的基础，是一种客户端-服务器协议。</p></li><li><p>HTTP/3</p><p>HTTP/3 是 HTTP 的下一个主要修订版。它运行在 QUIC 上，这是一种专为移动互联网使用而设计的新传输协议。它依赖于 UDP 而不是 TCP，从而实现更快的网页响应。 VR 应用程序需要更多带宽来渲染虚拟场景的复杂细节，并且可能会从迁移到由 QUIC 提供支持的 HTTP/3 中受益。</p></li><li><p>HTTPS（安全超文本传输协议）</p><p>HTTPS 扩展了 HTTP 并使用加密来实现安全通信。</p></li><li><p>WebSocket</p><p>WebSocket 是一种通过 TCP 提供全双工通信的协议。客户端建立WebSocket来接收来自后端服务的实时更新。与总是“拉取”数据的 REST 不同，WebSocket 允许“推送”数据。在线游戏、股票交易和消息传递应用程序等应用程序利用 WebSocket 进行实时通信。</p></li><li><p>TCP（传输控制协议）</p><p>TCP 旨在通过互联网发送数据包，并确保通过网络成功传送数据和消息。许多应用层协议构建在 TCP 之上。</p></li><li><p>UDP（用户数据报协议）</p><p>UDP 直接将数据包发送到目标计算机，无需先建立连接。 UDP 通常用于时间敏感的通信，其中偶尔丢弃数据包比等待更好。语音和视频流量通常使用此协议发送。</p></li><li><p>SMTP（简单邮件传输协议）</p><p>SMTP 是一种用于将电子邮件从一个用户传输到另一个用户的标准协议。</p></li><li><p>FTP（文件传输协议）</p><p>FTP 用于在客户端和服务器之间传输计算机文件。它具有单独的控制通道和数据通道连接。</p></li></ol>',4),l=[c];function a(_,s){return t(),p("div",null,l)}const r=e(o,[["render",a],["__file","一张图解释8种流行的网络协议.html.vue"]]);export{r as default};
